def bfs(node):
    queue = deque([node])
    distance = [-1] * n
    distance[node] = 0
    while queue:
        node = queue.popleft()
        for neighbor, weight in graph[node]:
            if distance[neighbor] == -1:
                distance[neighbor] = distance[node] + weight
                queue.append(neighbor)
    return distance


